INSERT INTO public.om_activity_years (activity_code, fiscal_year, service, appropriation, ba, sag_short_code, title, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$OM_AIRFOR_X_171$$, 2027, $$Air Force$$, $$OM_AIRFOR$$, NULL, NULL, $$DEPARTMENT OF THE AIR FORCE$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$, Subactivity Group 12A
